var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`타카나시 키아라는 그녀의 시청자, KFP를 위해 직접 쓴 편지를 낭독하기로 했다.`,JPN:`小鳥遊キアラは彼女のリスナー、KFPのために自筆の手紙を朗読すると決めた。`,ENG:`Takanashi Kiara decided to read a special letter that she has written for her loyal viewers, KFP.`,TWN:`Takanashi Kiara decided to read a special letter that she has written for her loyal viewers, KFP.`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`곧, 그녀가 무대 뒤에 도착했다는 무전이 들려왔다.`,JPN:`先ほど、彼女がバックステージに着いたとの連絡があった。`,ENG:`Soon, a radio call arrived saying that she has arrived backstage.`,TWN:`Soon, a radio call arrived saying that she has arrived backstage.`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`YOONA_CODEX_CLB_003`,text:{KOREA:`Kikkiriki, 내 소중한 KFP에게!`,JPN:`Kikkiriki, 私の大切なKFPへ!`,ENG:`Kikkiriki, my dear KFP!`,TWN:`Kikkiriki, my dear KFP!`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_CLB_003`,face:`UNIT_IDLE`},R:null}},voice:`clb003_lifetime_voice_201`},{id:`L9_1`,type:`dialog`,speaker:`YOONA_CODEX_CLB_003`,text:{KOREA:`먼저 내가 어느 곳에 있어도 날 찾아와 줘서 고맙다고 말하고 싶어!`,JPN:`まずは、私がどこにいても会いに来てくれてありがとうと言いたい！`,ENG:`I first wanted to say thank you for finding me wherever I go!`,TWN:`I first wanted to say thank you for finding me wherever I go!`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_CLB_003`,face:`UNIT_LAUGH`},R:null}},voice:`clb003_lifetime_voice_202`},{id:`L10_1`,type:`dialog`,speaker:`YOONA_CODEX_CLB_003`,text:{KOREA:`숨겨두었던 나의 아름다운 날개로 아주 멀리 날아가도 너라면 금방 날 찾을 수 있을 거야.`,JPN:`私が隠していた翼で遠くまで飛んで行っても、君ならすぐ私を見つけるだろうね。`,ENG:`I bet you can find and follow me anywhere even when I use these dazzling wings to travel great distances that I typically hide most of the time, though.`,TWN:`I bet you can find and follow me anywhere even when I use these dazzling wings to travel great distances that I typically hide most of the time, though.`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_CLB_003`,face:`UNIT_IDLE`},R:null}},voice:`clb003_lifetime_voice_203`},{id:`L11_1`,type:`dialog`,speaker:`YOONA_CODEX_CLB_003`,text:{KOREA:`그런데 그거 알아? 이 날개는 나만의 것이 아니야.`,JPN:`でも、知ってる？　この翼はね、私だけのものじゃないのよ。`,ENG:`You know something though? These wings are not just my own.`,TWN:`You know something though? These wings are not just my own.`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_CLB_003`,face:`UNIT_PRIDE`},R:null}},voice:`clb003_lifetime_voice_204`},{id:`L12_1`,type:`dialog`,speaker:`YOONA_CODEX_CLB_003`,text:{KOREA:`날개를 이루는 이 깃털들, 이게 다 너희 KFP라고!`,JPN:`この翼の羽一枚一枚が全部君たちKFPなの！`,ENG:`These feathers that make up these wings, these are you guys, KFP!`,TWN:`These feathers that make up these wings, these are you guys, KFP!`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_CLB_003`,face:`UNIT_LAUGH`},R:null}},voice:`clb003_lifetime_voice_205`},{id:`L13_1`,type:`dialog`,speaker:`YOONA_CODEX_CLB_003`,text:{KOREA:`물론, 나 혼자서도 재능 있고 섹시한 불사조가 될 순 있었겠지만, 날아오를 순 없었겠지.`,JPN:`もちろん、私一人でも才能豊かでセクシーなフェニックスになれたはずだけど、私一人だけだと空に羽ばたくのはきっとできなかったと思うわ。`,ENG:`Of course, I could have been a talented and hot phoenix on my own, but one that can’t fly.`,TWN:`Of course, I could have been a talented and hot phoenix on my own, but one that can’t fly.`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_CLB_003`,face:`UNIT_IDLE`},R:null}},voice:`clb003_lifetime_voice_206`},{id:`L14_1`,type:`dialog`,speaker:`YOONA_CODEX_CLB_003`,text:{KOREA:`너와 나 사이의 거리와는 상관없이, 네가 내 곁에 있어서 완전해질 수 있었던 거야.`,JPN:`君と私の間の距離は関係なく、君がそばにいてくれたから私は満たされたんだよ。`,ENG:`I am whole now because you guys are here with me, regardless of the distance between us.`,TWN:`I am whole now because you guys are here with me, regardless of the distance between us.`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_CLB_003`,face:`UNIT_IDLE`},R:null}},voice:`clb003_lifetime_voice_207`},{id:`L15_1`,type:`dialog`,speaker:`YOONA_CODEX_CLB_003`,text:{KOREA:`KFP와 함께라면, 이 화사한 날개로 무한히 성장하는 내 꿈을 향해 언제 어디서든 날아갈 수 있어.`,JPN:`KFPと一緒であれば、この派手な翼で成長し続ける私の夢へと、いつでもどこでも羽ばたいていけるはずよ。`,ENG:`With KFP, I was able to become a phoenix with vibrant wings that would allow me to travel anywhere at any time for my dreams to grow infinitely.`,TWN:`With KFP, I was able to become a phoenix with vibrant wings that would allow me to travel anywhere at any time for my dreams to grow infinitely.`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_CLB_003`,face:`UNIT_IDLE`},R:null}},voice:`clb003_lifetime_voice_208`},{id:`L16_1`,type:`dialog`,speaker:`YOONA_CODEX_CLB_003`,text:{KOREA:`자랑스러워해도 좋아. 아무나 불사조의 일부가 되는 게 아니라고?`,JPN:`誇りに思っていいわよ。フェニックスの一部なんて誰でもなれるわけじゃないからね。`,ENG:`You can be proud of it. One does not simply become a part of phoenix, you know?`,TWN:`You can be proud of it. One does not simply become a part of phoenix, you know?`},stage:{bg:`CLB_003`,bgm:`COLLABO_2022_02`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOONA_CODEX_CLB_003`,face:`UNIT_PRIDE`},R:null}},voice:`clb003_lifetime_voice_209`}];export{e as default};